import { AppError } from '../../errors/app-error.js';
import type { AuthenticatedActor } from '../auth/auth-session.service.js';
import type { PlatformStore } from '../projects/platform-store.js';
import type { ProjectAccessService } from '../projects/project-access.service.js';
import type { ProcessSummary, ProjectSummary } from '../../../shared/contracts/index.js';

export type ProcessAccessResult =
  | {
      kind: 'accessible';
      project: ProjectSummary;
      process: ProcessSummary;
    }
  | {
      kind: 'forbidden';
    }
  | {
      kind: 'project_not_found';
    }
  | {
      kind: 'process_not_found';
    };

export class ProcessAccessService {
  constructor(
    private readonly platformStore: PlatformStore,
    private readonly projectAccessService: ProjectAccessService,
  ) {}

  async getProcessAccess(args: {
    actor: AuthenticatedActor;
    projectId: string;
    processId: string;
  }): Promise<ProcessAccessResult> {
    const projectAccess = await this.projectAccessService.getProjectAccess({
      actor: args.actor,
      projectId: args.projectId,
    });

    if (projectAccess.kind === 'forbidden') {
      return {
        kind: 'forbidden',
      };
    }

    if (projectAccess.kind === 'not_found') {
      return {
        kind: 'project_not_found',
      };
    }

    const processRecord = await this.platformStore.getProcessRecord({
      processId: args.processId,
    });

    if (processRecord === null || processRecord.projectId !== args.projectId) {
      return {
        kind: 'process_not_found',
      };
    }

    return {
      kind: 'accessible',
      project: projectAccess.project,
      process: processRecord,
    };
  }

  async assertProcessAccess(args: {
    actor: AuthenticatedActor;
    projectId: string;
    processId: string;
  }): Promise<Extract<ProcessAccessResult, { kind: 'accessible' }>> {
    const access = await this.getProcessAccess(args);

    if (access.kind === 'accessible') {
      return access;
    }

    if (access.kind === 'forbidden') {
      throw new AppError({
        code: 'PROJECT_FORBIDDEN',
        message: 'You do not have access to this process.',
        statusCode: 403,
      });
    }

    if (access.kind === 'project_not_found') {
      throw new AppError({
        code: 'PROJECT_NOT_FOUND',
        message: 'The requested project was not found.',
        statusCode: 404,
      });
    }

    throw new AppError({
      code: 'PROCESS_NOT_FOUND',
      message: 'The requested process could not be found.',
      statusCode: 404,
    });
  }
}

import {
  buildProcessWorkSurfacePath,
  type ParsedRoute,
  parsedRouteSchema,
} from '../../shared/contracts/index.js';

function normalizePathname(pathname: string): string {
  const normalized = pathname.replace(/\/+$/, '');
  return normalized === '' ? '/' : normalized;
}

export function parseRoute(url: URL): ParsedRoute {
  const pathname = normalizePathname(url.pathname);

  if (pathname === '/projects') {
    return parsedRouteSchema.parse({
      kind: 'project-index',
      projectId: null,
      selectedProcessId: null,
      processId: null,
    });
  }

  const processMatch = pathname.match(/^\/projects\/([^/]+)\/processes\/([^/]+)$/);

  if (processMatch !== null) {
    const [, projectId, processId] = processMatch;

    return parsedRouteSchema.parse({
      kind: 'process-work-surface',
      projectId,
      selectedProcessId: null,
      processId,
    });
  }

  const projectMatch = pathname.match(/^\/projects\/([^/]+)$/);

  if (projectMatch !== null) {
    const [, projectId] = projectMatch;

    return parsedRouteSchema.parse({
      kind: 'project-shell',
      projectId,
      selectedProcessId: url.searchParams.get('processId'),
      processId: null,
    });
  }

  return parsedRouteSchema.parse({
    kind: 'project-index',
    projectId: null,
    selectedProcessId: null,
    processId: null,
  });
}

export function buildRouteHref(route: ParsedRoute): string {
  if (route.kind === 'project-index') {
    return '/projects';
  }

  if (route.kind === 'process-work-surface') {
    return buildProcessWorkSurfacePath({
      projectId: route.projectId ?? '',
      processId: route.processId ?? '',
    });
  }

  const url = new URL(`/projects/${route.projectId ?? ''}`, 'http://story0.local');

  if (route.selectedProcessId !== null) {
    url.searchParams.set('processId', route.selectedProcessId);
  }

  return `${url.pathname}${url.search}`;
}

export function navigateTo(
  route: ParsedRoute,
  options: { replace?: boolean } = {},
  targetWindow: Window & typeof globalThis = window,
): void {
  const nextHref = buildRouteHref(route);

  if (options.replace === true) {
    targetWindow.history.replaceState({}, '', nextHref);
    return;
  }

  targetWindow.history.pushState({}, '', nextHref);
}

